const withLog = fn => (...args) => {
  console.log('calling with', args);
  const r = fn(...args);
  console.log('=>', r);
  return r;
};
const add = (a, b) => a + b;
const loggedAdd = withLog(add);
loggedAdd(2, 3); // logs args, then 5

const pure = (a, b) => a + b;          // pure
let calls = 0;
const impure = (a, b) => { calls++; return a + b; }; // side effect

console.log(pure(2, 3), pure(2, 3));   // 5 5 (always)
impure(1, 1); impure(1, 1);
console.log('hidden state:', calls);   // 2 (not pure)

const counter = (function () {
  let count = 0;                 // private
  return { inc: () => ++count, value: () => count };
})();
counter.inc(); counter.inc();
console.log(counter.value());    // 2
console.log(typeof count);       // 'undefined' (not leaked)

function debounce(fn, ms) { let t; return (...a) => { clearTimeout(t); t = setTimeout(() => fn(...a), ms); }; }
function throttle(fn, ms) { let last = 0; return (...a) => { const n = Date.now(); if (n - last >= ms) { last = n; fn(...a); } }; }

const d = debounce(() => console.log('debounced'), 50);
const t = throttle(() => console.log('throttled'), 50);
d(); d(); d();   // 'debounced' once (after it goes quiet)
t(); t(); t();   // 'throttled' once (immediately, rest ignored)
